  ('dietitian-moex-11334', 'dietitian', 'dietitian-moex-093-2755cf97', 'sub-dietitian-05', NULL, 'single_choice', '有關血液透析與腹膜透析之敘述，何者正確？ 腹膜透析的透析效率較血液透析為差  病患若有凝血障礙，應選擇血液透析 血液透析會流失較多的蛋白質  腹膜透析對水分的控制應更為嚴格', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:59+00:00", "source_pdf_sha1": "8c35cacfa49d", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "093020", "c": "112", "s": "3001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "膳食療養學", "year": "093", "exam_name": "093年第一次專技醫事人員、中醫師、營養師、心理師、呼吸治療師、獸醫人員考試", "original_question_number": 27, "answer_corrected": false, "flags": ["answer_missing", "incomplete_options"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-11335', 'dietitian', 'dietitian-moex-093-2755cf97', 'sub-dietitian-05', NULL, 'single_choice', '若每星期血液透析三次，則每天每公斤體重給予多少公克蛋白質較適當？', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:59+00:00", "source_pdf_sha1": "8c35cacfa49d", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "093020", "c": "112", "s": "3001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "膳食療養學", "year": "093", "exam_name": "093年第一次專技醫事人員、中醫師、營養師、心理師、呼吸治療師、獸醫人員考試", "original_question_number": 28, "answer_corrected": false, "flags": ["answer_missing", "incomplete_options"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
